using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();
    private const double Delta = 0.001;

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, Delta);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        double result = _calc.CalculatePercentage(0, 10);
        Assert.AreEqual(0.0, result, Delta);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.AreEqual(70.0, result, Delta);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [DataTestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0,  "A")]  // boundary: exactly 90
    [DataRow(89.99, "B")]  // just below A
    [DataRow(80.0,  "B")]  // boundary: exactly 80
    [DataRow(79.99, "C")]  // just below B
    [DataRow(70.0,  "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0,  "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0,   "F")]
    public void GetGrade_BoundaryValues_ReturnsExpectedGrade(
        double percentage, string expectedGrade)
    {
        string grade = _calc.GetGrade(percentage);
        Assert.AreEqual(expectedGrade, grade);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        double result = _calc.NormalizeScore(50.0, 100.0);
        Assert.AreEqual(50.0, result, Delta);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        double result = _calc.NormalizeScore(120.0, 100.0);
        Assert.AreEqual(100.0, result, Delta);
    }

    [TestMethod]
    public void NormalizeScore_ResultIsNonNegative()
    {
        double result = _calc.NormalizeScore(0.0, 100.0);
        // No Assert.IsGreaterThanOrEqual — use Assert.IsTrue for comparisons
        Assert.IsTrue(result >= 0.0, $"Expected non-negative but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_ResultDoesNotExceed100()
    {
        double result = _calc.NormalizeScore(999.0, 50.0);
        Assert.IsTrue(result <= 100.0, $"Expected <= 100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50.0, 0.0));
    }
}

